INSERT INTO `tasks` (`id`, `user_id`, `title`, `description`, `image_path`, `revenue`, `status`, `is_paid`, `created_at`, `rating`, `is_archived`) VALUES
(1, 1013, 'Création affiche et bande annonce pour le film Amour perdu de Saba industrie', 'Création affiche pour annoncé que le film Amour perdu et renaissance seront bientôt disponible sur la plateforme WMA+ et la création d\'une bande annonce du film Amour perdu. Et l\'affiche du film casse tête.', 'uploads/tasks/task_6980c08d0bfc6.png', 0.00, 'termine', 0, '2026-02-02 15:19:41', 3, 1),
(2, 1007, 'Gestion et animation des réseaux sociaux de WMA Hub', '# **Objectifs de la mission**\r\n\r\n* Renforcer la visibilité et la notoriété de WMA Hub sur les réseaux sociaux.\r\n* Développer et engager la communauté en ligne.\r\n* Promouvoir les artistes, projets, services et actualités de WMA Hub.\r\n* Assurer une communication régulière, cohérente et professionnelle.\r\n* Améliorer l’interaction avec les abonnés (messages, commentaires, retours).\r\n* Suivre et analyser les performances afin d’optimiser la stratégie digitale.\r\n', NULL, 1.00, 'termine', 0, '2026-02-02 15:21:09', 3, 0),
(3, 1007, 'Gestion et animation des réseaux sociaux de WMA Hub', '# **Objectifs de la mission**\r\n\r\n* Renforcer la visibilité et la notoriété de WMA Hub sur les réseaux sociaux.\r\n* Développer et engager la communauté en ligne.\r\n* Promouvoir les artistes, projets, services et actualités de WMA Hub.\r\n* Assurer une communication régulière, cohérente et professionnelle.\r\n* Améliorer l’interaction avec les abonnés (messages, commentaires, retours).\r\n* Suivre et analyser les performances afin d’optimiser la stratégie digitale.\r\n', NULL, 1.00, 'termine', 0, '2026-02-02 15:21:20', 3, 0),
(4, 1034, 'Création des visuels promotionnels – Naskiss ft Shekeh', '### **Objectifs de la mission**\r\n\r\n* Concevoir **trois (3) designs graphiques professionnels** pour la promotion de la chanson de **Naskiss en featuring avec Shekeh**.\r\n* Assurer une identité visuelle cohérente et attractive, alignée avec l’univers artistique des deux artistes.\r\n* Renforcer l’impact visuel et la visibilité du projet sur les plateformes digitales et réseaux sociaux.\r\n\r\n### **Livrables attendus**\r\n\r\n1. **Affiche officielle** de la chanson.\r\n2. **Visuel “Coming Soon”** pour l’annonce avant sortie.\r\n3. **Visuel “Disponible”** pour accompagner la sortie officielle.\r\n\r\n### **Exigences**\r\n\r\n* Respect des formats adaptés aux réseaux sociaux et plateformes de streaming.\r\n* Qualité professionnelle (couleurs, typographie, composition).\r\n* Intégration claire des noms des artistes et du titre du projet.\r\n\r\n', NULL, 1.00, 'termine', 0, '2026-02-02 15:27:58', 3, 0),
(5, 1020, 'Communication digitale et relations publiques – WMA Plus', '# **Objectifs de la mission**\r\n\r\n* Assurer la communication globale de **WMA Plus** sur les supports digitaux et institutionnels.\r\n* Valoriser l’image de marque, les services et les projets de WMA Plus.\r\n* Rédiger et diffuser des contenus de communication clairs, cohérents et professionnels.\r\n* Couvrir et relayer les actualités, annonces, sorties musicales et événements.\r\n* Coordonner la communication entre les artistes, l’équipe interne et le public.\r\n* Veiller à la cohérence du message et au respect de l’identité de WMA Plus.\r\n* Proposer des stratégies et actions pour améliorer la visibilité et l’engagement.\r\n\r\n### **Résultats attendus**\r\n\r\n* Communication régulière et bien structurée.\r\n* Meilleure notoriété et crédibilité de WMA Plus.\r\n* Augmentation de l’engagement et de la portée des contenus.\r\n\r\n', NULL, 0.00, 'termine', 1, '2026-02-02 15:32:54', 3, 1),
(6, 1004, 'Secrétariat administratif et coordination – WMA Hub', '# **Objectifs de la mission**\r\n\r\n* Assurer la gestion administrative quotidienne de **WMA Hub**.\r\n* Organiser, classer et archiver les documents (contrats, courriers, rapports).\r\n* Gérer les appels, messages, e-mails et correspondances officielles.\r\n* Planifier les rendez-vous, réunions et agendas de la direction.\r\n* Rédiger les comptes rendus, notes internes et documents administratifs.\r\n* Assurer la liaison entre la direction, l’équipe interne, les artistes et les partenaires.\r\n* Veiller au respect des procédures internes et à la confidentialité des informations.\r\n\r\n### **Résultats attendus**\r\n\r\n* Organisation administrative efficace et fluide.\r\n* Meilleure coordination interne.\r\n* Image professionnelle et structurée de WMA Hub.\r\n', NULL, 1.00, 'termine', 1, '2026-02-02 15:35:10', 3, 1),
(7, 1013, 'Création bande annonce pour le film casse tête ', 'Création d\'une vidéo captivante d\'au moins 50sec pour annoncé la disponibilité du film casse tête sur WMA+. ', 'uploads/tasks/task_6980c460e8b33.png', 0.00, 'termine', 0, '2026-02-02 15:36:01', 3, 1),
(8, 1012, 'Direction générale et pilotage stratégique – WMA Hub', '# **Mission principale**\r\n\r\nAssurer la direction globale de **WMA Hub**, définir et piloter la stratégie de développement, garantir la performance opérationnelle et représenter officiellement l’entreprise auprès des partenaires, artistes et institutions.\r\n\r\n### **Objectifs de la mission**\r\n\r\n* Définir la vision, les orientations stratégiques et les objectifs de WMA Hub.\r\n* Superviser l’ensemble des départements (administration, communication, production, distribution, technique).\r\n* Prendre les décisions opérationnelles et stratégiques majeures.\r\n* Assurer la gestion financière et le suivi des performances de l’entreprise.\r\n* Développer des partenariats stratégiques et opportunités de croissance.\r\n* Garantir le respect des contrats, des procédures internes et des obligations légales.\r\n* Représenter WMA Hub auprès des artistes, investisseurs, médias et partenaires.\r\n* Veiller à la qualité des services et à la satisfaction des artistes et clients.\r\n\r\n### **Résultats attendus**\r\n\r\n* Croissance durable de WMA Hub.\r\n* Organisation interne efficace et performante.\r\n* Image crédible, professionnelle et influente de l’entreprise.\r\n', NULL, 1.00, 'termine', 0, '2026-02-02 15:37:16', 3, 0),
(9, 1027, 'Design graphique et identité visuelle – WMA Plus', '## **Mission principale**\r\n\r\nAssurer la création et le développement des supports visuels de **WMA Plus**, en respectant l’identité de la marque et en renforçant l’impact visuel des projets, artistes et services.\r\n\r\n### **Objectifs de la mission**\r\n\r\n* Concevoir des visuels graphiques pour la communication et la promotion (affiches, couvertures, bannières, flyers, contenus réseaux sociaux).\r\n* Développer et maintenir une identité visuelle cohérente pour WMA Plus.\r\n* Créer des visuels promotionnels pour les sorties musicales, événements et campagnes.\r\n* Adapter les designs aux différents formats digitaux et plateformes.\r\n* Collaborer avec l’équipe communication et marketing pour les campagnes visuelles.\r\n* Proposer des concepts créatifs innovants alignés avec la vision artistique de WMA Plus.\r\n* Assurer la qualité, la cohérence et le respect des délais de production.\r\n\r\n### **Résultats attendus**\r\n\r\n* Visuels professionnels, attractifs et cohérents.\r\n* Image forte et reconnaissable de WMA Plus.\r\n* Meilleure visibilité et impact des projets et artistes.', NULL, 0.00, 'en_cours', 0, '2026-02-02 15:40:35', 3, 0),
(10, 1061, 'Suivi, coordination et évaluation des projets – WMA Hub', '## **Mission principale**\r\n\r\nAssurer le suivi opérationnel des projets de **WMA Hub**, depuis la planification jusqu’à l’exécution, afin de garantir le respect des délais, des objectifs et de la qualité attendue.\r\n\r\n### **Objectifs de la mission**\r\n\r\n* Planifier, suivre et coordonner l’exécution des projets (artistiques, digitaux, événementiels).\r\n* Assurer la liaison entre les équipes internes, les artistes et les partenaires.\r\n* Suivre l’avancement des tâches et le respect des délais.\r\n* Identifier les risques, blocages et proposer des solutions adaptées.\r\n* Rédiger des rapports de suivi et comptes rendus d’avancement.\r\n* Veiller au respect des cahiers de charges et des objectifs fixés.\r\n* Assurer le contrôle qualité des livrables avant validation finale.\r\n* Informer régulièrement la direction de l’état d’avancement des projets.\r\n\r\n### **Résultats attendus**\r\n\r\n* Projets livrés dans les délais et selon les objectifs.\r\n* Meilleure coordination entre les équipes.\r\n* Réduction des retards et des dysfonctionnements.', NULL, 0.00, 'en_cours', 0, '2026-02-02 15:47:50', 3, 0),
(11, 1038, 'rthy5y5', '45y45y5y55t', NULL, 0.00, 'termine', 0, '2026-02-02 16:11:12', 3, 1),
(12, 1001, 'Chief Executive Officer (CEO) – WMA Hub', '# **Mission principale**\r\n\r\nDéfinir la vision globale de **WMA Hub**, piloter la stratégie à long terme et assurer la croissance, la performance et la pérennité de l’entreprise.\r\n\r\n### **Objectifs de la mission**\r\n\r\n* Définir la vision, la mission et les orientations stratégiques de WMA Hub.\r\n* Prendre les décisions stratégiques majeures et valider les projets clés.\r\n* Superviser la direction générale et l’ensemble des départements.\r\n* Assurer la croissance financière et le développement du business.\r\n* Développer et sécuriser des partenariats stratégiques.\r\n* Représenter officiellement WMA Hub auprès des investisseurs, partenaires et institutions.\r\n* Garantir la bonne gouvernance, la conformité légale et l’éthique de l’entreprise.\r\n* Veiller à l’innovation, à la compétitivité et à la qualité des services.\r\n\r\n### **Résultats attendus**\r\n\r\n* Croissance durable et structurée de WMA Hub.\r\n* Positionnement fort de la marque sur le marché.\r\n* Organisation performante et vision claire à long terme.\r\n', NULL, 0.00, 'termine', 1, '2026-02-02 16:19:01', 3, 1),
(13, 1013, 'Envoyer les fichiers dans la bases de données ', 'Télécharger tout les fichiers  dans base de données de WMA hub : design, contrat, flyers et autres supports.', 'uploads/tasks/task_6980d4f30849b.png', 0.00, 'termine', 0, '2026-02-02 16:46:44', 3, 1),
(14, 1022, 'Certification et vérification des comptes – Upendo Choir', '# **Mission principale**\r\n\r\nAssurer la **certification et la vérification des comptes** de **Upendo Choir** sur toutes les plateformes audio et services numériques, afin de garantir l’exactitude des données financières et la conformité des revenus générés.\r\n\r\n### **Objectifs de la mission**\r\n\r\n* Vérifier et certifier les informations des comptes Upendo Choir sur toutes les plateformes audio (Spotify, Audiomack, YouTube, etc.).\r\n* Contrôler l’exactitude des revenus, paiements et statistiques de streaming.\r\n* S’assurer que toutes les transactions respectent les normes et procédures en vigueur.\r\n* Établir des rapports de certification clairs et précis pour la direction et l’équipe de management.\r\n* Identifier et signaler toute anomalie ou incohérence dans les comptes.\r\n* Garantir la transparence et la fiabilité des informations financières pour la gestion des artistes.\r\n\r\n### **Résultats attendus**\r\n\r\n* Comptes certifiés et fiables.\r\n* Données financières exactes et conformes aux plateformes.\r\n* Rapports clairs pour la prise de décision et la gestion des revenus.\r\n', NULL, 0.00, 'en_cours', 0, '2026-02-02 19:39:46', 3, 0),
(15, 1013, 'Création d\'un vidéo ( maintenant disponible) pour GUL B ', 'Création d\'une vidéo de 40 sec pour la chanson loté de GUL avec la mention \"Maintenant disponible\'\' s\'inspirer des fichiers disponible dans la base de données de WMAHUB.\r\n\r\nA mettre sur la vidéo : \r\n- WMA hub logo\r\n- titre et Nom de l\'artiste \r\n- au dessus\" maintenant disponible \'', 'uploads/tasks/task_6981c9b67a251.png', 0.00, 'termine', 0, '2026-02-03 10:11:02', 3, 1),
(16, 1034, 'Conception d’une affiche communicationnelle – Nouvelle fonctionnalité WMA Hub', '**Mission principale**\r\n\r\nConcevoir une **affiche de communication officielle** pour **WMA Hub** afin d’informer les artistes et distributeurs qu’ils ont désormais la possibilité de **créer leurs comptes** et de **distribuer leurs projets de manière autonome** sur la plateforme.\r\n\r\n### **Objectifs de la mission**\r\n\r\n* Créer une affiche claire, moderne et professionnelle expliquant la nouvelle fonctionnalité de WMA Hub.\r\n* Mettre en valeur l’autonomie offerte aux **artistes** et **distributeurs**.\r\n* Renforcer la crédibilité et l’image innovante de la plateforme WMA Hub.\r\n* Faciliter la compréhension du processus d’inscription et d’accès aux espaces dédiés.\r\n\r\n### **Message clé à faire passer sur l’affiche**\r\n\r\n* Les artistes peuvent désormais créer leurs comptes et distribuer leurs projets eux-mêmes.\r\n* Les distributeurs disposent d’un **espace dédié** leur permettant de gérer et distribuer les projets de leurs artistes.\r\n\r\n### **Éléments obligatoires à intégrer sur l’affiche**\r\n\r\n* Lien d’inscription vers la plateforme **WMA Hub**.\r\n* Captures d’écran du **tableau de bord artiste**.\r\n* Captures d’écran du **tableau de bord distributeur**.\r\n* Logo WMA Hub et identité visuelle officielle.\r\n* Texte clair, lisible et orienté information.\r\n\r\n### **Résultats attendus**\r\n\r\n* Affiche communicationnelle professionnelle prête pour diffusion digitale.\r\n* Message clair et compréhensible pour les artistes et distributeurs.\r\n* Augmentation des inscriptions sur la plateforme WMA Hub.', 'uploads/tasks/task_6981e900d41ee.png', 0.00, 'assignee', 0, '2026-02-03 12:24:33', 3, 0),
(17, 1007, 'Post instagram ', 'L’EP « Follow » de l’artiste Dinno sera enfin disponible sur toutes les plateformes de téléchargement et de streaming ce 13 février.\r\nPréparez-vous à découvrir un projet fort, authentique et rempli d’émotions.\r\nRendez-vous le 13/02 🔥🎧', 'uploads/tasks/task_698489b15bb51.png', 0.00, 'termine', 1, '2026-02-05 12:14:42', 3, 1),
(18, 1007, 'Publication Resaux sociaux WMA HUB ', 'SHINOBI – ROMANTIC ❤️\r\nAprès Champion, Shinobi change de tempo et plonge dans l’univers de l’amour.\r\n\r\nUn titre doux, sincère et passionné, dédié aux cœurs amoureux.\r\n📅 Disponible le 13 février 2026\r\n🎧 Sur toutes les plateformes de streaming\r\n(Spotify, Audiomack, Deezer, Boomplay, Apple Music, YouTube)\r\n\r\n👉🏽 Disponible en pré-commander https://onerpm.link/Romantic-shinobi', 'uploads/tasks/task_6986eab1c942b.png', 0.00, 'termine', 1, '2026-02-07 07:33:07', 3, 1),
(19, 1013, 'Bande annonce ', 'Création d\'une vidéo captivante d\'au moins 50sec pour annoncé la diffusion du film choc partie 1 sur WMA+.', NULL, 1.00, 'termine', 0, '2026-02-13 12:11:01', 3, 1),
(20, 1013, 'Out now', 'Création d\'une vidéo de 40 sec pour la chanson Eva de bargoss et Aspino boy avec la mention \"Maintenant disponible\'\' s\'inspirer des fichiers disponible dans la base de données de WMAHUB.\r\n\r\nA mettre sur la vidéo :\r\n- WMA hub logo\r\n- titre et Nom de l\'artiste\r\n- au dessus\" maintenant disponible \'', NULL, 1.00, 'termine', 0, '2026-02-14 08:08:20', 3, 1),
(21, 1013, 'Création visuelle ', 'Création d\'un intro pour WMA+ et affiches pour le film Amour perdu de Saba industrie ', NULL, 1.00, 'termine', 0, '2026-02-28 14:51:42', 3, 0),
(22, 1013, 'ona ma nude ', 'hahahahahahahahahah', 'uploads/tasks/task_69a4224f9b1cb.jpeg', 2.00, '', 0, '2026-03-01 11:26:11', 3, 0),
(23, 1020, 'Publication sur Instagram et Facebook ', 'Publication de l\'affiche soon and now sur les réseaux sociaux, facebook et Instagram. Ainsi que la publication sur Tik Tok de la bande annonce du film Amour perdu demain mercredi a 10h heure de GOMA. Partager dans les groupes facebook pour plus de visibilité et sur les statuts whatsapp.', NULL, 2.00, 'assignee', 0, '2026-03-03 19:53:21', 3, 0),
(24, 1013, 'Bande annonce ', 'Création d\'une bande annonce pour la deuxième partie du film choc et de l\'affiche bientôt disponible ', NULL, 0.00, 'en_cours', 0, '2026-03-03 19:54:42', 3, 0);
